+type reloadState struct {
+	mu      sync.RWMutex
+	status  api_v1.ReloadStatus
+	path    string
+	enabled bool
+}
+
+func newReloadState(dir string, enabled bool) *reloadState {
+	s := &reloadState{status: api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}}, path: filepath.Join(dir, reloadStatusFilename), enabled: enabled}
+	if !enabled {
+		return s
+	}
+	b, err := os.ReadFile(s.path)
+	if err != nil {
+		return s
+	}
+	var status api_v1.ReloadStatus
+	if json.Unmarshal(b, &status) == nil && validReloadStatus(status) {
+		if status.AppliedReloaders == nil {
+			status.AppliedReloaders = []string{}
+		}
+		if status.ReloaderTimingsMS == nil {
+			status.ReloaderTimingsMS = map[string]float64{}
+		}
+		s.status = status
+	}
+	return s
+}
+
+func validReloadStatus(s api_v1.ReloadStatus) bool {
+	switch s.ErrorCategory {
+	case "none", "load_error", "apply_error", "rollback_error":
+		return true
+	default:
+		return false
+	}
+}
+
+func (s *reloadState) Status() api_v1.ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	result := s.status
+	result.AppliedReloaders = append([]string{}, s.status.AppliedReloaders...)
+	result.ReloaderTimingsMS = make(map[string]float64, len(s.status.ReloaderTimingsMS))
+	for k, v := range s.status.ReloaderTimingsMS {
+		result.ReloaderTimingsMS[k] = v
+	}
+	return result
+}
+
+func (s *reloadState) Record(status api_v1.ReloadStatus) {
+	if !s.enabled {
+		return
+	}
+	s.mu.Lock()
+	s.status = status
+	b, err := json.Marshal(status)
+	if err == nil {
+		_ = os.MkdirAll(filepath.Dir(s.path), 0o755)
+		_ = os.WriteFile(s.path+".tmp", b, 0o644)
+		_ = os.Rename(s.path+".tmp", s.path)
+	}
+	s.mu.Unlock()
+}
