+// reloadConfigTransactional applies reloaders in order and restores the last
+// known-good configuration when a partially applied reload fails.
+func reloadConfigTransactional(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), state *reloadState, lastGood **config.Config, initial bool, rls ...reloader) (err error) {
+	start := time.Now()
+	status := api_v1.ReloadStatus{LastReloadID: start.UTC().Format(time.RFC3339Nano), ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}}
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+			status.LastReloadSuccessful = true
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+		if !initial {
+			state.Record(status)
+		}
+	}()
+
+	logger.Info("Loading configuration file", "filename", filename)
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		status.ErrorCategory = "load_error"
+		status.ErrorMessage = err.Error()
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	for _, rl := range rls {
+		rstart := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = float64(time.Since(rstart)) / float64(time.Millisecond)
+		if err != nil {
+			status.ErrorCategory = "apply_error"
+			status.ErrorMessage = err.Error()
+			status.FailedReloader = rl.name
+			if len(status.AppliedReloaders) > 0 && *lastGood != nil {
+				status.RollbackAttempted = true
+				status.RollbackSuccessful = true
+				for _, rollback := range rls {
+					if rollbackErr := rollback.reloader(*lastGood); rollbackErr != nil {
+						status.RollbackSuccessful = false
+						status.ErrorCategory = "rollback_error"
+						status.ErrorMessage = rollbackErr.Error()
+						status.FailedReloader = rollback.name
+						break
+					}
+				}
+			}
+			return fmt.Errorf("error applying configuration with reloader %q: %w", rl.name, err)
+		}
+		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	*lastGood = conf
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return nil
+}
